import React from 'react';
import { fade, makeStyles } from '@material-ui/core/styles';
import AppBar from '@material-ui/core/AppBar';
import Toolbar from '@material-ui/core/Toolbar';
import Grid from '@material-ui/core/Grid';
import IconButton from '@material-ui/core/IconButton';
import Badge from '@material-ui/core/Badge';
import MenuItem from '@material-ui/core/MenuItem';
import Menu from '@material-ui/core/Menu';
import Button from '@material-ui/core/Button';
import ExpandMoreOutlinedIcon from '@material-ui/icons/ExpandMoreOutlined';
import SettingsIcon from '@material-ui/icons/Settings';
import ReportProblemOutlinedIcon from '@material-ui/icons/ReportProblemOutlined';
import AccountCircle from '@material-ui/icons/AccountCircle';
import Typography from '@material-ui/core/Typography';

class NavBar extends React.Component {
    constructor(props) {
      super(props);
      this.state = {
        fields : this.props.fields,
        user: this.props.user,
        anchorEl: null,
        field: this.props.fields[0],
        url: this.props.url,
      }

      this.handleClick = (e) => {console.log("hice un click");this.setState({ anchorEl: e.currentTarget}); console.log(this.state)};
      this.handleClose = (e) => {
        console.log(e);
        this.setState({ anchorEl: null })
      };
      this.handleChange = (e) => this.setState({[e.target.name]: e.target.value});
    }
    render(){
        return(
          <AppBar position="static">
            <Toolbar>
              <Grid container spacing={1}>
                <Grid xs={10} style={{textAlign :'center'}} item={true}>
                <Button aria-controls="simple-menu" aria-haspopup="true" style={{color: 'white'}} onClick={this.handleClick} endIcon={<ExpandMoreOutlinedIcon />}>
                  {this.state.field.name}
                </Button>
                    <Menu
                    style={{minWidth : '250px'}}
                    id="menu-appbar"
                    anchorEl={this.state.anchorEl}
                    keepMounted
                    open={Boolean(this.state.anchorEl)}
                    onClose={this.handleClose}
                    >
                      <MenuItem name="field" onClick={this.handleClose.bind(this, 'AGRICOLA RIO PEUMO')}>AGRICOLA RIO PEUMO </MenuItem>
                      <MenuItem name="field" onClick={this.handleClose.bind(this, 'CONCHA Y TORO')}>CONCHA Y TORO</MenuItem>
                      <MenuItem name="field" onClick={this.handleClose.bind(this, 'CASABLANCA')}>CASABLANCA</MenuItem>
                  </Menu>
                </Grid>
                <Grid container xs={2} style={{display: "inline-flex"}}>
                  <Grid xs={4} item={true}>
                    <IconButton aria-label="show 4 new mails" color="inherit">
                      <SettingsIcon />
                    </IconButton>
                  </Grid>
                  <Grid item={true} xs={4}>
                    <IconButton aria-label="show 17 new notifications" color="inherit"
                      onClick="#">
                      <Badge badgeContent={3} color="light" style={{ width: '20px',height: '18px'}}>
                        <ReportProblemOutlinedIcon />
                      </Badge>
                    </IconButton>
                  </Grid>
                  <Grid item={true} xs={4}>   
                    <IconButton
                      edge="end"
                      aria-label="account of current user"
                      aria-haspopup="true"
                      onClick="#"
                      color="inherit"
                    >
                      <AccountCircle />
                    </IconButton>
                  </Grid>                  
                </Grid>
              </Grid>
            </Toolbar>
            <Toolbar color="primary-light" style={{ backgroundColor: '#9CF7EB', color: 'black', minHeight: '35px'}}>
              <Grid item={true} style={{textAlign: 'left'}}>
                <Typography style={{fontWeight: 'bold'}} variant="subtitle1">{ this.state.url }</Typography>
              </Grid>
            </Toolbar>
          </AppBar>
        )
    }
        
}
export default NavBar;