import React from 'react';
import 'typeface-roboto';
import {withRouter} from 'react-router-dom';
import Button from '@material-ui/core/Button';
import Grid from '@material-ui/core/Grid';
import Card from '@material-ui/core/Card';
import TextField from '@material-ui/core/TextField';
import FormControlLabel from '@material-ui/core/FormControlLabel';
import CardContent from '@material-ui/core/CardContent';
import Checkbox from '@material-ui/core/Checkbox';
//import Typography from '@material-ui/core/Typography';
import Link from '@material-ui/core/Link';




class Login extends React.PureComponent {
  constructor(props) {
    super(props);
    this.state = {
      email: "",
      password: "",
    };

    this.handleLoginSubmit = this.handleLoginSubmit.bind(this);
    this.handleChange = (e) => this.setState({[e.target.name]: e.target.value});
    
  }

  //Si el usuario ha sido logeado para desarrollar despues
  componentDidMount(){
    if (sessionStorage.getItem("userLoged")) window.location.href = "/contratos";
  }

  handleLoginSubmit(e) {
    e.preventDefault();
    console.log(this.state);
    const data = {
      email: this.state.email,
      password: this.state.password
    }
    window.location.href = "/home";
  }

 

  render() {
    return (

      <Grid container spacing={0} direction="column" alignItems="center" justify="center" style={{ minHeight: '100vh' }}>
        <Grid item xs={3}>
          <Card raised style={{width: '400px'}}>
            <CardContent style={{padding: '40px'}}>
              <form noValidate onSubmit={e => this.handleLoginSubmit(e)}>
                <TextField
                  variant="filled"
                  margin="normal"
                  value={this.state.email} 
                  onChange={this.handleChange}
                  fullWidth
                  id="email"
                  label="Email"
                  name="email"
                  style={{marginBottom: '10px'}}
                />
                <TextField
                  variant="filled"
                  margin="normal"
                  value={this.state.password} 
                  onChange={this.handleChange}
                  fullWidth
                  name="password"
                  label="Contraseña"
                  type="password"
                  id="password"
                  style={{marginBottom: '10px'}}
                />
                <Grid container
                  direction="row"
                  justify="center"
                  alignItems="center"
                  style={{ marginTop: '6%', marginBottom: '6%'}}>
                  <Grid xs={6} item={true}>
                    <FormControlLabel
                      control={<Checkbox value="remember" color="primary" />}
                      label="Recordarme"
                    />
                  </Grid>
                  <Grid xs={6} item={true}>
                    <Link>
                      Olvide mi contraseña
                    </Link>
                  </Grid>
                </Grid>

                <Button
                  type="submit"
                  fullWidth
                  variant="contained"
                  color="primary"
                >
                  Login
                </Button>
              </form>
            </CardContent>
          </Card>
        </Grid>   
      </Grid> 
    )
  }
}

export default withRouter(Login);