import React from 'react';
import './App.css';
import Routes from './routes';
import { createMuiTheme,ThemeProvider } from '@material-ui/core/styles';

const theme = createMuiTheme({
  palette: {
    primary: {
      main: '#0097a7',
      light: '#9CF7EB',
      dark: '#359389'
    },
    secondary: {
      main: '#B6BFB6',
      light: '#868F86',
      darl: '#E8F2E8',
    },
  },
});



function App() {
  return (
    <ThemeProvider theme={theme}>
      <Routes />
    </ThemeProvider>
  );
}

export default App;
