import React from 'react';
import {Link, withRouter} from 'react-router-dom';
import Grid from '@material-ui/core/Grid';
import NavBar from './navBar';
import {ReactComponent as IconCapitalHumano} from '../assets/img/icon_capital_humano.svg';
import {ReactComponent as IconClima} from '../assets/img/icon_clima.svg';
import {ReactComponent as IconFuenteAgua} from '../assets/img/icon_fuentes_de_agua.svg';
import {ReactComponent as IconIndicadores} from '../assets/img/icon_indicadores.svg';
import {ReactComponent as IconPlant} from '../assets/img/icon_planta.svg';
import {ReactComponent as IconRiego} from '../assets/img/icon_riego.svg';
import {ReactComponent as IconSoporte} from '../assets/img/icon_soporte.svg';
import {ReactComponent as IconSuelo} from '../assets/img/icon_suelo.svg';
import IconButton from '@material-ui/core/IconButton';
import Typography  from '@material-ui/core/Typography';





class Home extends React.PureComponent {
  constructor(props) {
    super(props);
    console.log(this.props)
    this.state = {
      fields: [
        {
          name:  'Agricola Rio Peumo',
        }
      ],
      user: {
        nombre: 'Test',
      },
      url: 'Home'
    };

    this.handleGo = this.handleGo.bind(this);
  }

  handleGo(e){
    e.preventDefault();
    console.log(this.state);
    window.location.href = "/indicadores";
  }

  render() {
    return (
      <div>
        <NavBar url={this.state.url} user={this.state.user} fields={this.state.fields} />
        <Grid style={{ paddingRight: '10%',paddingLeft: '10%',paddingTop: '5%'}} container spacing={1}>
          <Grid xs={3} style={{textAlign :'center'}} item={true}>
            <IconButton onClick={this.handleGo}  aria-label="delete" style={{ padding: '25px', border: "1px solid #0097a7", borderRadius: '15%'}}color="primary">
              <IconIndicadores />
            </IconButton>
            <Typography variant="h6" style={{paddingTop: '5%', textTransform: 'uppercase'}} color="primary">Indicadores</Typography>
          </Grid>
          <Grid xs={3} style={{textAlign :'center'}} item={true}>
            <IconButton  aria-label="delete" style={{  padding: '25px', border: "1px solid #0097a7", borderRadius: '15%'}}color="primary">
              <IconRiego />
            </IconButton>
            <Typography variant="h6" style={{paddingTop: '5%', textTransform: 'uppercase'}} color="primary">Riego</Typography>
          </Grid>
          <Grid xs={3} style={{textAlign :'center'}} item={true}>
            <IconButton  aria-label="delete" style={{  padding: '25px', border: "1px solid #0097a7", borderRadius: '15%'}}color="primary">
              <IconPlant />
            </IconButton>
            <Typography variant="h6" style={{paddingTop: '5%', textTransform: 'uppercase'}} color="primary">Planta</Typography>
          </Grid>
          <Grid xs={3} style={{textAlign :'center'}} item={true}>
            <IconButton aria-label="delete" style={{  padding: '25px', border: "1px solid #0097a7", borderRadius: '15%'}}color="primary">
              <IconSuelo />
            </IconButton>
            <Typography variant="h6" style={{paddingTop: '5%', textTransform: 'uppercase'}} color="primary">Suelo</Typography>
          </Grid>
        </Grid>
        <Grid style={{marginTop: '2%', paddingRight: '10%',paddingLeft: '10%'}} container spacing={1}>
          <Grid xs={3} style={{textAlign :'center'}} item={true}>
            <IconButton  aria-label="delete" style={{ padding: '25px', border: "1px solid #0097a7", borderRadius: '15%'}}color="primary">
              <IconClima />
            </IconButton>
            <Typography variant="h6" style={{paddingTop: '5%', textTransform: 'uppercase'}} color="primary">Clima</Typography>
          </Grid>
          <Grid xs={3} style={{textAlign :'center'}} item={true}>
            <IconButton  aria-label="delete" style={{  padding: '25px', border: "1px solid #0097a7", borderRadius: '15%'}}color="primary">
              <IconCapitalHumano />
            </IconButton>
            <Typography variant="h6" style={{paddingTop: '5%', textTransform: 'uppercase'}} color="primary">Capital humano</Typography>
          </Grid>
          <Grid xs={3} style={{textAlign :'center'}} item={true}>
            <IconButton  aria-label="delete" style={{  padding: '25px', border: "1px solid #0097a7", borderRadius: '15%'}}color="primary">
              <IconSoporte />
            </IconButton>
            <Typography variant="h6" style={{paddingTop: '5%', textTransform: 'uppercase'}} color="primary">Soporte</Typography>
          </Grid>
          <Grid xs={3} style={{textAlign :'center'}} item={true}>
            <IconButton aria-label="delete" style={{  padding: '25px', border: "1px solid #0097a7", borderRadius: '15%'}}color="primary">
              <IconFuenteAgua />
            </IconButton>
            <Typography variant="h6" style={{paddingTop: '5%', textTransform: 'uppercase'}} color="primary">Fuentes Agua</Typography>
          </Grid>
        </Grid>

      </div>
     

    )
  }
}

export default withRouter(Home);
