import React from 'react';
import {Link, withRouter} from 'react-router-dom';
import NavBar from './navBar';
import Grid from '@material-ui/core/Grid';
import Table from '@material-ui/core/Table';
import TableBody from '@material-ui/core/TableBody';
import TableCell from '@material-ui/core/TableCell';
import TableContainer from '@material-ui/core/TableContainer';
import TableHead from '@material-ui/core/TableHead';
import TableRow from '@material-ui/core/TableRow';
import Paper from '@material-ui/core/Paper';
import Typography from '@material-ui/core/Typography'
import GetAppIcon from '@material-ui/icons/GetApp';
import IconButton from '@material-ui/core/IconButton';
import FiberManualRecordIcon from '@material-ui/icons/FiberManualRecord';
import EditIcon from '@material-ui/icons/Edit';


//Data necesaria
const rows = [
  createData('2013 - 2', -4.00, -0.07, 3.93, 756.00, false),
  createData('2013 - 1', -4.50, 0.43, 4.74, 420.10, false),
  createData('2013 - 3', -4.50, 0.43, 4.74, 514.00, false),
  createData('2013 - 5', -4.50, 0.43, 4.93, 528.00, false),
  createData('2014 - 2', -4.00, -0.07, 5.00, 632.20, false),
  createData('2017 - 3', -5.50, 1.43, 5.00, 185.00, 801.00),
];

const headCells = [
  { id: 'sector', numeric: false, disablePadding: true, label: 'Sector' },
  { id: 'waterPotencial', numeric: true, disablePadding: false, label: 'Potencial Hídrico' },
  { id: 'difference', numeric: true, disablePadding: false, label: 'Diferencia' },
  { id: 'etc', numeric: true, disablePadding: false, label: 'mm Etc' },
  { id: 'lastWatering', numeric: true, disablePadding: false, label: 'mm Último riego' },
  { id: 'program', numeric: false, disablePadding: false, label: 'Pre-programación' },
];

function createData(sector, waterPotencial, difference, etc, lastWatering, program) {
  return { sector, waterPotencial, difference, etc, lastWatering, program };
}

class Indicators extends React.PureComponent {
  constructor(props) {
    super(props);
    console.log(props);
    this.state = {
      url: 'Indicadores',
      user: 'test',
      fields: [
        {
          name:  'Agricola Rio Peumo',
        }
      ],
    };


    
  }

 

  render() {
    return (
      <div>
        <NavBar url={this.state.url} user={this.state.user} fields={this.state.fields} />
        <Grid container style={{marginTop: '4%'}}>
          <Grid item={true}>

          </Grid>
          <Grid item={true} style={{textAling: "right"}}>
          <Grid container spacing={1} style={{width: '100%',padding: '2%',backgroundColor: '#0097a7',margin: '0px'}}>
            <Grid xs={10}>
              <Typography variant="subtitle1" style={{color : 'white', textAlign: 'center'}}>Ultima medición</Typography>
              <Typography variant="h6" style={{color : 'white', textAlign: 'center'}}>LUNES 20 DE ENERO 2020</Typography>
            </Grid>
            <Grid xs={2}>
              <IconButton aria-label="show 4 new mails" style={{ marginTop: '5%',fontSize: 'initial',color: 'white',backgroundColor: '#46b7a8',borderRadius: '15%'}}>
                <GetAppIcon /> Exportar
              </IconButton>
            </Grid>
          </Grid>
          <TableContainer component={Paper}>
            <Table aria-label="customized table">
              <TableHead>
                <TableRow>
                  <TableCell align="center" style={{color: '#868F86'}}>Sector</TableCell>
                  <TableCell align="center" style={{color: '#868F86'}}>Potencial Hídrico</TableCell>
                  <TableCell align="center" style={{color: '#868F86'}}>Diferencia</TableCell>
                  <TableCell align="center" style={{color: '#868F86'}}>mm ETS</TableCell>
                  <TableCell align="center" style={{color: '#868F86'}}>mm Último riego</TableCell>
                  <TableCell align="center" style={{color: '#868F86'}}>Pre-programación</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {rows.map(row => (
                  <TableRow key={row.name}>
                    <TableCell align="center" style={{color: '#868F86'}}>{row.sector}</TableCell>
                    <TableCell align="center" style={{color: '#868F86'}}>{row.waterPotencial}</TableCell>
                    {
                      (Math.abs(row.waterPotencial) > row.etc ) ?
                        <TableCell align="center" style={{color: '#868F86'}}>{row.difference}<FiberManualRecordIcon style={{width: '0.6em',height: '0.6em',color: '#11b911'}}></FiberManualRecordIcon></TableCell>
                      : 
                        [
                          ((Math.abs(row.waterPotencial)- row.etc) < -1 ) ?
                          <TableCell align="center" style={{color: '#868F86'}}>{row.difference}<FiberManualRecordIcon style={{width: '0.6em',height: '0.6em',color: '#f44336;'}}></FiberManualRecordIcon></TableCell>
                          :
                          [
                            ((Math.abs(row.waterPotencial)- row.etc) > -1 && ((Math.abs(row.waterPotencial)- row.etc) < 0 ) ) ?
                              < TableCell align="center" style={{color: '#868F86'}}>{row.difference}<FiberManualRecordIcon style={{width: '0.6em',height: '0.6em',color: 'rgb(223, 232, 22)'}}></FiberManualRecordIcon></TableCell>
                            :
                            <TableCell align="center" style={{color: '#868F86'}}>{row.difference}<FiberManualRecordIcon style={{width: '0.6em',height: '0.6em',color:'#e45454'}}></FiberManualRecordIcon></TableCell>
                          ]
       
                        ]
                      
                    }
                    <TableCell align="center" style={{color: '#868F86'}}>{row.etc}</TableCell>
                    <TableCell align="center" style={{color: '#868F86'}}>{row.lastWatering}</TableCell>
                    {
                      (row.program) ?
                      <TableCell align="center" style={{color: '#868F86'}}>{row.program}</TableCell>
                      :
                      <TableCell align="center" style={{color: '#868F86'}}>
                        <IconButton color="primary" aria-label="show 4 new mails" style={{fontSize: '0.6rem',borderRadius: '45%'}}>
                          <EditIcon /> Crear pre-programación
                        </IconButton>
                    </TableCell>
                    }
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
          </Grid>
        </Grid>
        <Grid container>

        </Grid>
      </div>
    )
  }
}

export default withRouter(Indicators);